import React, { useEffect, useState } from "react";
import axios from "axios";

export default function DashboardDisciplinas() {
  const [disciplinas, setDisciplinas] = useState([]);
  const [disciplinaSelecionada, setDisciplinaSelecionada] = useState(null);
  const [agendamentosFiltrados, setAgendamentosFiltrados] = useState([]);
  const [carregandoAgendamentos, setCarregandoAgendamentos] = useState(false);

  // Busca disciplinas só uma vez
  useEffect(() => {
    axios.get("/api/disciplinas").then(res => setDisciplinas(res.data));
  }, []);

  // Função para buscar agendamentos ao clicar no card
  function buscarAgendamentosDaDisciplina(disciplina) {
    setDisciplinaSelecionada(disciplina);
    setCarregandoAgendamentos(true);
    axios.get(`/api/agendamentos?disciplinaId=${disciplina.id}`)
      .then(res => setAgendamentosFiltrados(res.data))
      .finally(() => setCarregandoAgendamentos(false));
  }

  return (
    <div className="max-w-7xl mx-auto py-8 px-4">
      <h1 className="text-2xl font-bold mb-6 text-[#1d3557]">Disciplinas</h1>

      {/* Cards das disciplinas */}
      <div className="flex flex-wrap gap-6 mb-10">
        {disciplinas.map((disc) => (
          <button
            key={disc.id}
            className={`min-w-[200px] flex-1 rounded-2xl px-6 py-8 shadow-md text-left border-2 transition
              ${disciplinaSelecionada?.id === disc.id 
                ? "border-[#3172C0] bg-[#f1f6fd]" 
                : "border-transparent bg-white hover:border-[#3172C0] hover:bg-[#f7fafc]"}`}
            onClick={() => buscarAgendamentosDaDisciplina(disc)}
          >
            <div className="font-bold text-lg text-[#3172C0] mb-1">{disc.nome}</div>
            <div className="text-gray-600 text-sm">{disc.periodo_nome} {disc.turno}</div>
            {/* Você pode remover a linha abaixo ou mostrar um loading, pois agora só busca ao clicar */}
            {/* <div className="mt-2 text-sm text-gray-400">
              {agendamentosFiltrados.length} agendamentos
            </div> */}
          </button>
        ))}
      </div>

      {/* Lista de agendamentos da disciplina selecionada */}
      {disciplinaSelecionada && (
        <div className="bg-white rounded-2xl shadow border">
          <h2 className="text-lg font-semibold px-6 pt-6 pb-2">
            Agendamentos de <span className="text-[#3172C0]">{disciplinaSelecionada.nome}</span>
          </h2>
          <div className="overflow-x-auto">
            <table className="min-w-full mt-2">
              <thead>
                <tr className="border-b bg-gray-100 text-gray-600 text-left">
                  <th className="py-3 px-4 font-semibold">Operador</th>
                  <th className="py-3 px-4 font-semibold">Auxiliar</th>
                  <th className="py-3 px-4 font-semibold">Período</th>
                  <th className="py-3 px-4 font-semibold">Disciplina</th>
                  <th className="py-3 px-4 font-semibold">Paciente</th>
                  <th className="py-3 px-4 font-semibold">Data</th>
                  <th className="py-3 px-4 font-semibold">Hora</th>
                  <th className="py-3 px-4 font-semibold">Status</th>
                  <th className="py-3 px-4 font-semibold text-right">Ações</th>
                </tr>
              </thead>
              <tbody>
                {carregandoAgendamentos ? (
                  <tr>
                    <td colSpan={9} className="py-6 text-center text-gray-400">
                      Carregando agendamentos...
                    </td>
                  </tr>
                ) : agendamentosFiltrados.length === 0 ? (
                  <tr>
                    <td colSpan={9} className="py-6 text-center text-gray-400">
                      Nenhum agendamento para esta disciplina.
                    </td>
                  </tr>
                ) : (
                  agendamentosFiltrados.map((ag) => (
                    <tr key={ag.id} className="border-b last:border-b-0 hover:bg-gray-50">
                      <td className="py-3 px-4">{ag.operadorNome}</td>
                      <td className="py-3 px-4">{ag.auxiliarNome}</td>
                      <td className="py-3 px-4">{ag.periodo_nome}</td>
                      <td className="py-3 px-4">{disciplinaSelecionada.nome}</td>
                      <td className="py-3 px-4">{ag.pacienteNome}</td>
                      <td className="py-3 px-4">{ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}</td>
                      <td className="py-3 px-4">{ag.hora}</td>
                      <td className="py-3 px-4">
                        <span className="px-3 py-1 rounded-full text-xs font-semibold bg-blue-100 text-blue-700">
                          {ag.status}
                        </span>
                      </td>
                      <td className="py-3 px-4 text-right flex gap-2">
                        <button
                          onClick={() => alert(`Editar agendamento ${ag.id}`)}
                          className="px-3 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
                        >
                          Editar
                        </button>
                        <button
                          onClick={() => alert(`Deletar agendamento ${ag.id}`)}
                          className="px-3 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
                        >
                          Deletar
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
